import java.util.Scanner;

public class SecureXSSExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input to prevent XSS attacks
        String sanitizedUserInput = sanitizeInput(userInput);

        String welcomeMessage = "Hello, " + sanitizedUserInput + "!";

        System.out.println(welcomeMessage);
    }

    private static String sanitizeInput(String input) {
        // Replace potentially dangerous characters with safe equivalents
        return input.replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("&", "&amp;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
